# ! [doc = " Default value application for LinkML slots"] # ! [doc = ""] # ! [doc = " This module handles the ifabsent logic for applying default values"] # ! [doc = " to slots when values are missing."] use chrono :: { Local , Utc } ; use linkml_core :: types :: { IfAbsentAction , SchemaDefinition } ; use serde_json :: Value ; use std :: collections :: HashMap ; # [doc = " Apply default values to data based on schema definitions"] pub struct DefaultApplier < 'a > { schema : & 'a SchemaDefinition , } impl < 'a > DefaultApplier < 'a > { # [doc = " Create a new default applier"] pub fn new (schema : & 'a SchemaDefinition) -> Self { Self { schema } } # [doc = " Create from schema (alias for new)"] pub fn from_schema (schema : & 'a SchemaDefinition) -> Self { Self :: new (schema) } # [doc = " Apply defaults to a JSON value"] pub fn apply_defaults (& self , data : & mut Value , schema : & SchemaDefinition ,) -> Result < () , String > { let obj = data . as_object_mut () . ok_or_else (| | "Data must be an object" . to_string ()) ? ; let class_name = obj . get ("@type") . and_then (| v | v . as_str ()) . map (String :: from) . or_else (| | schema . classes . keys () . next () . cloned ()) . ok_or_else (| | "Cannot determine class for defaults" . to_string ()) ? ; self . apply_defaults_to_object (obj , & class_name) } # [doc = " Apply defaults to an object map"] pub fn apply_defaults_to_object (& self , data : & mut serde_json :: Map < String , Value > , class_name : & str ,) -> Result < () , String > { let class = self . schema . classes . get (class_name) . ok_or_else (| | format ! ("Class '{}' not found" , class_name)) ? ; for slot_name in & class . slots { if data . contains_key (slot_name) { continue ; } if let Some (slot) = self . schema . slots . get (slot_name) { if let Some (ifabsent) = & slot . ifabsent { let default_value = self . compute_default_value (ifabsent , slot_name , class_name , data) ? ; if let Some (value) = default_value { data . insert (slot_name . clone () , value) ; } } } } for (slot_name , slot_override) in & class . slot_usage { if data . contains_key (slot_name) { continue ; } if let Some (ifabsent) = & slot_override . ifabsent { let default_value = self . compute_default_value (ifabsent , slot_name , class_name , data) ? ; if let Some (value) = default_value { data . insert (slot_name . clone () , value) ; } } } Ok (()) } # [doc = " Compute the default value based on IfAbsentAction"] fn compute_default_value (& self , action : & IfAbsentAction , slot_name : & str , class_name : & str , data : & serde_json :: Map < String , Value > ,) -> Result < Option < Value > , String > { match action { IfAbsentAction :: SlotName => { Ok (Some (Value :: String (slot_name . to_string ()))) } IfAbsentAction :: ClassName => { Ok (Some (Value :: String (class_name . to_string ()))) } IfAbsentAction :: ClassSlotCurie => { let curie = format ! ("{}:{}" , class_name , slot_name) ; Ok (Some (Value :: String (curie))) } IfAbsentAction :: Bnode => { let bnode = format ! ("_:b{}" , uuid :: Uuid :: new_v4 () . simple ()) ; Ok (Some (Value :: String (bnode))) } IfAbsentAction :: DefaultValue => { Ok (None) } IfAbsentAction :: String (s) => { Ok (Some (Value :: String (s . clone ()))) } IfAbsentAction :: Date => { let date = Local :: now () . format ("%Y-%m-%d") . to_string () ; Ok (Some (Value :: String (date))) } IfAbsentAction :: Datetime => { let datetime = Utc :: now () . to_rfc3339 () ; Ok (Some (Value :: String (datetime))) } IfAbsentAction :: Int (n) => { Ok (Some (Value :: Number ((* n) . into ()))) } IfAbsentAction :: Expression (expr) => { let data_hashmap : HashMap < String , Value > = data . iter () . map (| (k , v) | (k . clone () , v . clone ())) . collect () ; self . evaluate_expression (expr , & data_hashmap) } } } # [doc = " Evaluate an expression to produce a default value"] fn evaluate_expression (& self , expression : & str , data : & HashMap < String , Value > ,) -> Result < Option < Value > , String > { if expression . contains ('{') && expression . contains ('}') { let mut result = expression . to_string () ; let re = regex :: Regex :: new (r"\{([^}]+)\}") . expect ("Operation failed") ; for cap in re . captures_iter (expression) { if let Some (var_name) = cap . get (1) { if let Some (value) = data . get (var_name . as_str ()) { if let Some (str_val) = value . as_str () { result = result . replace (& format ! ("{{{}}}" , var_name . as_str ()) , str_val) ; } } } } Ok (Some (Value :: String (result))) } else { Ok (Some (Value :: String (expression . to_string ()))) } } } # [doc = " Integration with the validation context"] pub fn apply_defaults_to_instance (schema : & SchemaDefinition , instance : & mut Value , class_name : & str ,) -> Result < () , String > { let applier = DefaultApplier :: new (schema) ; if let Value :: Object (map) = instance { applier . apply_defaults_to_object (map , class_name) ? ; } Ok (()) } # [cfg (test)] mod tests { use super :: * ; use linkml_core :: types :: { ClassDefinition , IfAbsentAction , SchemaDefinition , SlotDefinition } ; # [test] fn test_slot_name_default () { let mut schema = SchemaDefinition :: default () ; let mut slot = SlotDefinition :: default () ; slot . name = "identifier" . to_string () ; slot . ifabsent = Some (IfAbsentAction :: SlotName) ; schema . slots . insert ("identifier" . to_string () , slot) ; let mut class = ClassDefinition :: default () ; class . name = "Person" . to_string () ; class . slots = vec ! ["identifier" . to_string ()] ; schema . classes . insert ("Person" . to_string () , class) ; let mut data = serde_json :: json ! ({ "name" : "John" }) ; let applier = DefaultApplier :: new (& schema) ; applier . apply_defaults (& mut data , & schema) . unwrap () ; if let Value :: Object (ref mut obj) = data { applier . apply_defaults_to_object (obj , "Person") . unwrap () ; } assert_eq ! (data . get ("identifier") , Some (& Value :: String ("identifier" . to_string ()))) ; } # [test] fn test_bnode_generation () { let mut schema = SchemaDefinition :: default () ; let mut slot = SlotDefinition :: default () ; slot . name = "id" . to_string () ; slot . ifabsent = Some (IfAbsentAction :: Bnode) ; schema . slots . insert ("id" . to_string () , slot) ; let mut class = ClassDefinition :: default () ; class . name = "Entity" . to_string () ; class . slots = vec ! ["id" . to_string ()] ; schema . classes . insert ("Entity" . to_string () , class) ; let mut data1 = serde_json :: json ! ({ }) ; let mut data2 = serde_json :: json ! ({ }) ; let applier = DefaultApplier :: new (& schema) ; if let Value :: Object (ref mut obj) = data1 { applier . apply_defaults_to_object (obj , "Entity") . unwrap () ; } if let Value :: Object (ref mut obj) = data2 { applier . apply_defaults_to_object (obj , "Entity") . unwrap () ; } let id1 = data1 . get ("id") . unwrap () . as_str () . unwrap () ; let id2 = data2 . get ("id") . unwrap () . as_str () . unwrap () ; assert ! (id1 . starts_with ("_:b")) ; assert ! (id2 . starts_with ("_:b")) ; assert_ne ! (id1 , id2) ; } # [test] fn test_expression_default () { let mut schema = SchemaDefinition :: default () ; let mut slot = SlotDefinition :: default () ; slot . name = "full_id" . to_string () ; slot . ifabsent = Some (IfAbsentAction :: Expression ("{prefix}_{number}" . to_string ())) ; schema . slots . insert ("full_id" . to_string () , slot) ; let mut class = ClassDefinition :: default () ; class . name = "Item" . to_string () ; class . slots = vec ! ["full_id" . to_string () , "prefix" . to_string () , "number" . to_string () ,] ; schema . classes . insert ("Item" . to_string () , class) ; let mut data = serde_json :: json ! ({ "prefix" : "ITEM" , "number" : "123" }) ; let applier = DefaultApplier :: new (& schema) ; if let Value :: Object (ref mut obj) = data { applier . apply_defaults_to_object (obj , "Item") . unwrap () ; } assert_eq ! (data . get ("full_id") , Some (& Value :: String ("ITEM_123" . to_string ()))) ; } }
